ActorManager = {}

local actors = {}

function ActorManager:init()
    for _, setting in pairs(ActorConfig.settings) do
        local actor = GameActor.new(setting)
        self:addActor(actor)
    end
end

function ActorManager:addActor(actor)
   actors[actor.entityId] = actor
end

function ActorManager:removeActor(actor)
    actors[actor.entityId] = nil
end

function ActorManager:getActor(childEntityId)
    for _, actor in pairs(actors) do
        if actor.entityId == childEntityId then
            return actor
        end
    end
    return nil
end

function ActorManager:getActors()
    return actors
end

